import { useQuery, QueryClient } from '@tanstack/react-query';

const queryClient = new QueryClient();

function UserList() {
  const { data, isLoading } = useQuery({
    queryKey: ['users'],
    queryFn: () => fetch('/api/users').then(res => res.json())
  });
  return isLoading ? null : data;
}
